import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.encoder.Encode;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Validate user input (e.g., check for null or empty values)
        if (userInput == null || userInput.isEmpty()) {
            response.getWriter().println("<p>Invalid input</p>");
            return;
        }

        // Encode user input to prevent XSS attacks
        String encodedUserInput = Encode.forHtml(userInput);

        response.getWriter().println("<p>User input: " + encodedUserInput + "</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
